md.paddingY: {spacing.sm} → var(--semantic-spacing-sm)
md.fontSize: {font.size.md} → var(--semantic-font-size-md)
lg.paddingX: {spacing.md} → var(--semantic-spacing-md)
lg.paddingY: {spacing.sm} → var(--semantic-spacing-sm)
lg.fontSize: {font.size.lg} → var(--semantic-font-size-lg)

## Do & Don't
✅ **Do**
- Utiliser les CSS custom properties (var(--component-*))
- Respecter les états interactifs (hover, active, focus, disabled)
- Vérifier la fidélité visuelle avec la maquette Figma

❌ **Don't**
- Ne pas utiliser de valeurs brutes (px, #hex) — utiliser les tokens
- Ne pas supprimer les états d'accessibilité (:focus-visible)
- Ne pas modifier les dimensions sans vérifier la spec Figma

## 💻 Code interactif (Live Editor)

```jsx
const __css = `.input {
  display: flex;
  align-items: center;
  width: 100%;
  font-family: var(--semantic-font-family-default, Inter);
  font-weight: 400;
  border-radius: var(--component-input-radius, var(--semantic-radius-md, 8px));
  border: var(--semantic-border-width-default, 1px) solid var(--semantic-color-border-default, #D1D5DB);
  background: var(--semantic-color-bg-primary, #FFFFFF);
  color: var(--semantic-color-text-primary, #111827);
  transition: border-color 150ms ease-in-out, box-shadow 150ms ease-in-out;
  outline: none;
  box-sizing: border-box;
}
.input::placeholder { color: var(--semantic-color-text-tertiary, #9CA3AF); }
.input:hover:not(:disabled):not(.input--error) { border-color: var(--semantic-color-border-strong, #9CA3AF); }
.input:focus-visible, .input--focus {
  border-color: var(--semantic-color-border-focus, #3B82F6);
  box-shadow: 0 0 0 2px var(--semantic-color-border-focus, #3B82F6);
  border-width: 2px;
}
.input--error { border-color: var(--semantic-color-danger-500, #DC2626); }
.input:disabled, .input--disabled {
  background: var(--semantic-color-bg-disabled, #F9FAFB);
  color: var(--semantic-color-text-disabled, #D1D5DB);
  border-color: var(--semantic-color-border-disabled, #E5E7EB);
  cursor: not-allowed;
}

/* Sizes */
.input--sm {
  padding: var(--semantic-spacing-xs, 4px) var(--semantic-spacing-sm, 8px);
  font-size: var(--semantic-font-size-sm, 14px);
  line-height: 20px;
  min-height: 32px;
}
.input--md {
  padding: var(--semantic-spacing-sm, 8px);
  font-size: var(--semantic-font-size-md, 16px);
  line-height: 24px;
  min-height: 40px;
}
.input--lg {
  padding: var(--semantic-spacing-sm, 8px) var(--semantic-spacing-md, 16px);
  font-size: var(--semantic-font-size-lg, 18px);
  line-height: 28px;
  min-height: 48px;
}`;

const Input = ({
  size = "md",
  state,
  placeholder = "Placeholder",
  disabled = false,
  id,
  label,
  ...props
}) => {
  const stateClass = state === "error" ? "input--error"
    : state === "focus" ? "input--focus"
    : state === "disabled" ? "input--disabled"
    : "";
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
      {label && <label htmlFor={id} style={{ fontSize: 14, fontWeight: 500 }}>{label}</label>}
      <input
        id={id}
        className={`input input--${size} ${stateClass}`}
        disabled={disabled || state === "disabled"}
        placeholder={placeholder}
        aria-invalid={state === "error"}
        {...props}
      />
    </div>
  );
};

// Demo
const InputDemo = () => (
  <div style={{ display: "flex", flexDirection: "column", gap: 12, padding: 16, maxWidth: 320 }}>
    <Input size="sm" label="Small" id="i-sm" placeholder="Small input" />
    <Input size="md" label="Medium" id="i-md" placeholder="Medium input" />
    <Input size="lg" label="Large" id="i-lg" placeholder="Large input" />
    <Input size="md" state="focus" label="Focus" id="i-focus" placeholder="Focused" />
    <Input size="md" state="error" label="Error" id="i-err" placeholder="Error state" />
    <Input size="md" state="disabled" label="Disabled" id="i-dis" placeholder="Disabled" />
  </div>
);

render(<><style>{__css}</style><Input /></>);
```

## ⚠️ Tokens manquants (à créer dans Figma)
--semantic-color-bg-primary | background | #FFFFFF
--semantic-color-bg-disabled | background:disabled | #F9FAFB
--semantic-color-text-primary | color | #111827
--semantic-color-text-tertiary | placeholder color | #9CA3AF
--semantic-color-text-disabled | color:disabled | #D1D5DB
--semantic-color-border-default | border-color | #D1D5DB
--semantic-color-border-strong | border-color:hover | #9CA3AF
--semantic-color-border-focus | border-color:focus | #3B82F6
--semantic-color-danger-500 | border-color:error | #DC2626
--semantic-color-border-disabled | border-color:disabled | #E5E7EB

card.description:
## Description développeur
Composant généré par le pipeline IA avec fidélité pixel-perfect Figma. À compléter par le développeur.

## Token Mapping (Figma → CSS)
padding.sm → var(--spacing-md) [16px]
padding.md → var(--spacing-lg) [24px]
padding.lg → var(--spacing-xl) [32px]
radius → var(--radius-lg) [12px]
bg → var(--color-bg-primary) [#FFFFFF]
border → var(--color-border-default) [#E5E7EB]
shadow → var(--shadow-100) [0px 1px 3px 0px rgba(0,0,0,0.1)]

## Do & Don't
✅ **Do**
- Utiliser les CSS custom properties (var(--component-*))
- Respecter les états interactifs (hover, active, focus, disabled)
- Vérifier la fidélité visuelle avec la maquette Figma

❌ **Don't**
- Ne pas utiliser de valeurs brutes (px, #hex) — utiliser les tokens
- Ne pas supprimer les états d'accessibilité (:focus-visible)
- Ne pas modifier les dimensions sans vérifier la spec Figma

## 💻 Code interactif (Live Editor)

```jsx
const __css = `.card {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 0;
  background: var(--color-bg-primary, #FFFFFF);
  border: 1px solid var(--color-border-default, #E5E7EB);
  border-radius: var(--radius-lg, 12px);
  box-shadow: var(--shadow-100, 0px 1px 3px 0px rgba(0,0,0,0.1));
}
.card--sm { padding: var(--spacing-md, 16px); }
.card--md { padding: var(--spacing-lg, 24px); }
.card--lg { padding: var(--spacing-xl, 32px); }`;

const Card = ({ size = 'md', children, className = '', ...props }) => (
  <div className={`card card--${size} ${className}`} {...props}>
    {children}
  </div>
);

// Demo
const CardDemo = () => (
  <div style={{display:'flex',gap:16,flexWrap:'wrap'}}>
    {['sm','md','lg'].map(s => (
      <Card key={s} size={s}><p style={{margin:0}}>Card {s.toUpperCase()}</p></Card>
    ))}
  </div>
);

render(<><style>{__css}</style><Card /></>);
```

## ⚠️ Tokens manquants (à créer dans Figma)
--spacing-md: padding SM → 16px
--spacing-lg: padding MD → 24px
--spacing-xl: padding LG → 32px
--radius-lg: border-radius → 12px
--color-bg-primary: background → #FFFFFF
--color-border-default: border color → #E5E7EB
--shadow-100: box-shadow → 0px 1px 3px 0px rgba(0,0,0,0.1)

